import { moduleMetadata } from '@storybook/angular';
import { PfAlertComponent } from './alert.component';
const meta = {
    title: 'Composants/Alert',
    component: PfAlertComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Message contextuel inline. 4 sévérités (info, success, warning, danger), optionnellement fermable, ARIA approprié. [→ Description complète & bonnes pratiques](?path=/docs/documentation-générale-composants-alert--docs)",
            },
        },
    },
    decorators: [
        moduleMetadata({ imports: [PfAlertComponent] }),
        (storyFn) => {
            const story = storyFn();
            return { ...story, template: `<div style="width: 480px;">${story.template}</div>` };
        },
    ],
    argTypes: {
        severity: { control: 'inline-radio', options: ['info', 'success', 'warning', 'danger'] },
        dismissible: { control: 'boolean' },
    },
    args: {
        severity: 'info',
        title: 'Information',
        dismissible: false,
    },
    render: (args) => ({
        props: args,
        template: `<pf-alert [severity]="severity" [title]="title" [dismissible]="dismissible">
      Un message contextuel pour accompagner l'utilisateur.
    </pf-alert>`,
    }),
};
export default meta;
export const Info = {};
export const Success = {
    args: { severity: 'success', title: 'Action réalisée' },
};
export const Warning = {
    args: { severity: 'warning', title: 'Attention' },
};
export const Danger = {
    args: { severity: 'danger', title: 'Erreur' },
};
export const Dismissible = {
    args: { dismissible: true },
};
export const NoTitle = {
    args: { title: '' },
};
export const AllSeverities = {
    render: () => ({
        template: `
      <div style="display: flex; flex-direction: column; gap: 12px;">
        <pf-alert severity="info" title="Info">Texte explicatif.</pf-alert>
        <pf-alert severity="success" title="Succès">Tout s'est bien passé.</pf-alert>
        <pf-alert severity="warning" title="Attention">Point à vérifier.</pf-alert>
        <pf-alert severity="danger" title="Erreur">Quelque chose a échoué.</pf-alert>
      </div>
    `,
    }),
};
